#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 32) {
        std::sort(arr.begin(), arr.end());
        return;
    }

    // Check for already sorted prefix
    auto it = std::is_sorted_until(arr.begin(), arr.end());
    if (it == arr.end()) return;

    // Handle "mostly sorted" (elements appended at the end)
    if ((arr.end() - it) <= 32) {
        std::sort(it, arr.end());
        std::inplace_merge(arr.begin(), it, arr.end());
        return;
    }

    // Check for reverse-sorted data
    if (std::is_sorted(arr.rbegin(), arr.rend())) {
        std::reverse(arr.begin(), arr.end());
        return;
    }

    // Fallback to standard Introsort
    std::sort(arr.begin(), arr.end());
}

